using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class AzureSqlQueryFunction
{
    [FunctionName("AzureSqlQueryFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        var connectionString = Environment.GetEnvironmentVariable("SQLConnectionString");
        var queryParameters = req.Query;
        string sqlQuery = "SELECT * FROM YourTable WHERE 1=1";

        foreach (var param in queryParameters)
        {
            if (param.Key.StartsWith("filter"))
            {
                sqlQuery += $" AND {param.Key.Substring(6)} = @{param.Key.Substring(6)}";
            }
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
